// Extract tool call data from the VAPI webhook payload
const body = $input.first().json.body;

if (!body || !body.message) {
  throw new Error('Invalid VAPI webhook payload: missing body.message');
}

const message = body.message;
const toolCallList = message.toolCallList;

if (!toolCallList || toolCallList.length === 0) {
  throw new Error('No tool calls found in VAPI message');
}

const toolCall = toolCallList[0];
const args = toolCall.function?.arguments || toolCall.arguments || {};

// Parse arguments if they come as a JSON string
const parsedArgs = typeof args === 'string' ? JSON.parse(args) : args;

return [{
  json: {
    toolCallId: toolCall.id,
    query: parsedArgs.query,
    callId: message.call?.id || ''
  }
}];

// Format the retrieved chunks into a VAPI tool result response
const allItems = $input.all();

// Get toolCallId from the Extract Tool Call node
const toolCallId = $('Extract Tool Call').first().json.toolCallId;

// Build context string from retrieved document chunks
let contextText = '';

if (allItems && allItems.length > 0) {
  const chunks = allItems
    .map((item, i) => {
      const content = item.json.pageContent || item.json.content || item.json.text || '';
      return content.trim().length > 0 ? `[Excerpt ${i + 1}]: ${content.trim()}` : null;
    })
    .filter(Boolean);

  if (chunks.length > 0) {
    contextText = `Here is relevant information from the RelayPay knowledge base:\n\n${chunks.join('\n\n')}`;
  }
}

if (!contextText) {
  contextText = 'No relevant information was found in the RelayPay knowledge base for that question. Please let the user know you cannot find documentation on that topic and offer to escalate if needed.';
}

// VAPI expects this exact response format for tool results
return [{
  json: {
    results: [
      {
        toolCallId: toolCallId,
        result: contextText
      }
    ]
  }
}];
